def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio > 2:
            score = 1000 + 20 * (ratio - 1.5)**3
            for j in range(i):
                if bins[j] > capacity:
                    score += 5 * (bins[j] - capacity) / capacity
        elif ratio > 1:
            score = 500 + 15 * (ratio - 1)**2
            if capacity < 20:
                score += 10
            for j in range(i+1, len(bins)):
                if bins[j] < capacity / 2:
                    score -= 3
        else:
            if ratio > 0.75:
                score = 80 * ratio + capacity * 0.01
            elif ratio > 0.5:
                score = 40 * ratio + capacity * 0.02
            else:
                score = 10 * ratio + capacity * 0.03
            if capacity < 10:
                score += 10
            elif capacity > 100:
                score -= 10
            for k in range(len(bins)):
                if k != i and bins[k] < capacity:
                    score += 0.5 * (capacity - bins[k]) / capacity
        if i % 3 == 0:
            score *= 1.2
        elif i % 3 == 1:
            score *= 0.85
        else:
            score *= 0.95
        if i > 0 and priorities[i-1] > score:
            score += 2 * (priorities[i-1] - score)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if len(finite_priorities) == 0:
        return priorities
    min_priority = np.min(finite_priorities)
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority + 100
        elif priorities[i] < min_priority + 10:
            priorities[i] += (max_priority - priorities[i]) * 0.05
    return priorities
